local typeUITraceScroll = typeof(CS.UITraceScroll)
local UIListBase = UIListBase
---@class UIListTrace:UIListBase
local UIListTrace = LxClass("UIListTrace", UIListBase)

function UIListTrace:UIListTrace()
	self._csTraceViewContent = nil
	self._csTraceViewBackground = nil
end

function UIListTrace:Create(parentWnd, scrollTrans)
	if (not parentWnd) then
		LogError("need parentWnd")
		return false
	end
	if (not scrollTrans) then
		LogError("need objScroll")
		return false
	end
	self._isMultScroll = false
	self._parentWnd = parentWnd
	self._scrollTrans = scrollTrans

	self._dataTable = LXFW.LxKVList:New()
	self._groupTable = LXFW.LxKVList:New()

	local csUIScroll = scrollTrans:GetComponent(typeUITraceScroll)
	if (not csUIScroll) then
		LogError("need csUITraceScroll")
		return false
	end

	self._parentWnd = parentWnd
	self._csUIScroll = csUIScroll
	csUIScroll.stopThreshold = 10
	csUIScroll.speedScale = 1
	csUIScroll.velocityScale = 20

	self._csTraceViewContent = csUIScroll.ContentView
	self._csTraceViewBackground = csUIScroll.BackgroundView

	if self._parentWnd then
		self._parentWnd:OnWndListCreate(self)
	end
	
	return true
end

function UIListTrace:SetStopThreshold(threshold)
	local csUIScroll = self._csUIScroll
	if csUIScroll then
		csUIScroll.stopThreshold = threshold
	end
end

function UIListTrace:SetSpeedScale(scale)
	local csUIScroll = self._csUIScroll
	if csUIScroll then
		csUIScroll.speedScale = scale
	end
end

function UIListTrace:SetVelocityScale(scale)
	local csUIScroll = self._csUIScroll
	if csUIScroll then
		csUIScroll.velocityScale = scale
	end
end

function UIListTrace:SetFuncOnItemDraw(funcVal)
	UIListBase.SetFuncOnItemDraw(self, funcVal)
	if (funcVal) then
		self._csTraceViewContent.onItemDraw = function(...) self:OnItemDraw(...) end
	else
		self._csTraceViewContent.onItemDraw = nil
	end
end

function UIListTrace:SetBackgroundCount(count)
	self._csTraceViewBackground.DataCount = count
end

---@param refreshMode number @recommend 0 从头刷新 1 指定位置
---@param refreshCustom number|nil @recommend refreshMode = 1 有效，指定刷新位置
function UIListTrace:RefreshList(refreshMode, refreshCustom, bReset)
	if CS.IsNullObject(self._scrollTrans)  then
		return
	end
	
	if self._refreshName ~= "RefreshList" then
		self._refreshName = "RefreshList"
		self._refreshCount = 0
	end
	
	self._touchBeginMoveX = nil
	self._touchBeginMoveY = nil
	
	refreshMode = refreshMode or 0
	refreshCustom = refreshCustom or 0
	self._isResetWithoutAni = bReset
	if not bReset then
		self._refreshCount = self._refreshCount + 1
	end
	
	local dataCnt = self:GetDataSize()
	self._csTraceViewContent.DataCount = dataCnt
	self:SetBackgroundCount(dataCnt)
	-- 防止列表关闭后的刷新
	if CS.IsNullObject(self:GetScrollTrans()) then
		return
	end
	
	self._csUIScroll:DoRefreshToTarget(refreshMode, refreshCustom)
end

function UIListTrace:ResetList(centerPos,speed)
	self._isResetWithoutAni = true
	self:RefreshList(refreshMode, refreshCustom, true)
end

